#include <stdlib.h>
#include <math.h>
#include <string.h>
#include <stdio.h>
#include <omp.h>

#include "define.c"

extern params_common common;
extern params_common_change common_change;
extern params_unique punt[ALL_POINTS];

void kernel_function(int bx) {

    fp* d_in;
    int rot_row;
    int rot_col;
    int in2_rowlow;
    int in2_collow;
    int ic;
    int jc;
    int jp1;
    int ja1, ja2;
    int ip1;
    int ia1, ia2;
    int ja, jb;
    int ia, ib;
    float s;
    int i;
    int j;
    int row;
    int col;
    int ori_row;
    int ori_col;
    int position;
    float sum;
    int pos_ori;
    float temp;
    float temp2;
    int location;
    int cent;
    int tMask_row;
    int tMask_col;
    float largest_value_current = 0;
    float largest_value = 0;
    int largest_coordinate_current = 0;
    int largest_coordinate = 0;
    float fin_max_val = 0;
    int fin_max_coo = 0;
    int largest_row;
    int largest_col;
    int offset_row;
    int offset_col;

    float in_partial_sum[51];
    float in_sqr_partial_sum[51];
    float in_final_sum;
    float in_sqr_final_sum;
    float mean;
    float mean_sqr;
    float variance;
    float deviation;
    float denomT;
    float par_max_val[131];
    int   par_max_coo[131];
    int pointer;
    float d_in_mod_temp[2601];
    int ori_pointer;
    int loc_pointer;
    int ei_new;

    //===============================================================================
    // GENERATE TEMPLATE
    //===============================================================================

    if (common_change.frame_no == 0) {

        d_in = &punt[bx].d_T[punt[bx].in_pointer];

        // Update row/col loc
        pointer = punt[bx].point_no * common.no_frames + common_change.frame_no;
        punt[bx].d_tRowLoc[pointer] = punt[bx].d_Row[punt[bx].point_no];
        punt[bx].d_tColLoc[pointer] = punt[bx].d_Col[punt[bx].point_no];

        // Create templates
        ei_new = 0;
        while (ei_new < common.in_elem) {
            row = (ei_new + 1) % common.in_rows - 1;
            col = (ei_new + 1) / common.in_rows + 1 - 1;
            if ((ei_new + 1) % common.in_rows == 0) {
                row = common.in_rows - 1;
                col = col - 1;
            }

            ori_row = punt[bx].d_Row[punt[bx].point_no] - 25 + row - 1;
            ori_col = punt[bx].d_Col[punt[bx].point_no] - 25 + col - 1;
            ori_pointer = ori_col * common.frame_rows + ori_row;

            d_in[col * common.in_rows + row] = common_change.d_frame[ori_pointer];

            ei_new = ei_new + 1;
        }
    }

    //===============================================================================
    // PROCESS POINTS
    //===============================================================================

    if (common_change.frame_no != 0) {

        //==========================================================================
        // SELECTION
        //==========================================================================

        in2_rowlow = punt[bx].d_Row[punt[bx].point_no] - common.sSize;
        in2_collow = punt[bx].d_Col[punt[bx].point_no] - common.sSize;

        ei_new = 0;
        while (ei_new < common.in2_elem) {
            row = (ei_new + 1) % common.in2_rows - 1;
            col = (ei_new + 1) / common.in2_rows + 1 - 1;
            if ((ei_new + 1) % common.in2_rows == 0) {
                row = common.in2_rows - 1;
                col = col - 1;
            }

            ori_row = row + in2_rowlow - 1;
            ori_col = col + in2_collow - 1;
            punt[bx].d_in2[ei_new] = common_change.d_frame[ori_col * common.frame_rows + ori_row];

            ei_new = ei_new + 1;
        }

        //==========================================================================
        // CONVOLUTION
        //==========================================================================

        // ROTATION
        d_in = &punt[bx].d_T[punt[bx].in_pointer];

        ei_new = 0;
        while (ei_new < common.in_elem) {
            row = (ei_new + 1) % common.in_rows - 1;
            col = (ei_new + 1) / common.in_rows + 1 - 1;
            if ((ei_new + 1) % common.in_rows == 0) {
                row = common.in_rows - 1;
                col = col - 1;
            }

            rot_row = (common.in_rows - 1) - row;
            rot_col = (common.in_rows - 1) - col;
            d_in_mod_temp[ei_new] = d_in[rot_col * common.in_rows + rot_row];

            ei_new = ei_new + 1;
        }

        // ACTUAL CONVOLUTION
        ei_new = 0;
        while (ei_new < common.conv_elem) {
            ic = (ei_new + 1) % common.conv_rows;
            jc = (ei_new + 1) / common.conv_rows + 1;
            if ((ei_new + 1) % common.conv_rows == 0) {
                ic = common.conv_rows;
                jc -= 1;
            }

            j = jc + common.joffset;
            jp1 = j + 1;
            if (common.in2_cols < jp1) {
                ja1 = jp1 - common.in2_cols;
            } else {
                ja1 = 1;
            }
            if (common.in_cols < j) {
                ja2 = common.in_cols;
            } else {
                ja2 = j;
            }

            i = ic + common.ioffset;
            ip1 = i + 1;

            if (common.in2_rows < ip1) {
                ia1 = ip1 - common.in2_rows;
            } else {
                ia1 = 1;
            }
            if (common.in_rows < i) {
                ia2 = common.in_rows;
            } else {
                ia2 = i;
            }

            s = 0;
            for (ja = ja1; ja <= ja2; ja++) {
                jb = jp1 - ja;
                for (ia = ia1; ia <= ia2; ia++) {
                    ib = ip1 - ia;
                    s = s + d_in_mod_temp[common.in_rows * (ja - 1) + ia - 1] * punt[bx].d_in2[common.in2_rows * (jb - 1) + ib - 1];
                }
            }

            punt[bx].d_conv[ei_new] = s;

            ei_new = ei_new + 1;
        }

        //==========================================================================
        // CUMULATIVE SUM
        //==========================================================================

        // PAD ARRAY
        ei_new = 0;
        while (ei_new < common.in2_pad_cumv_elem) {
            row = (ei_new + 1) % common.in2_pad_cumv_rows - 1;
            col = (ei_new + 1) / common.in2_pad_cumv_rows + 1 - 1;
            if ((ei_new + 1) % common.in2_pad_cumv_rows == 0) {
                row = common.in2_pad_cumv_rows - 1;
                col = col - 1;
            }

            if (row > (common.in2_pad_add_rows - 1) &&
                row < (common.in2_pad_add_rows + common.in2_rows) &&
                col > (common.in2_pad_add_cols - 1) &&
                col < (common.in2_pad_add_cols + common.in2_cols)) {
                ori_row = row - common.in2_pad_add_rows;
                ori_col = col - common.in2_pad_add_cols;
                punt[bx].d_in2_pad_cumv[ei_new] = punt[bx].d_in2[ori_col * common.in2_rows + ori_row];
            } else {
                punt[bx].d_in2_pad_cumv[ei_new] = 0;
            }

            ei_new = ei_new + 1;
        }

        // VERTICAL CUMULATIVE SUM
        ei_new = 0;
        while (ei_new < common.in2_pad_cumv_cols) {
            pos_ori = ei_new * common.in2_pad_cumv_rows;
            sum = 0;
            for (position = pos_ori; position < pos_ori + common.in2_pad_cumv_rows; position += 1) {
                punt[bx].d_in2_pad_cumv[position] = punt[bx].d_in2_pad_cumv[position] + sum;
                sum = punt[bx].d_in2_pad_cumv[position];
            }
            ei_new = ei_new + 1;
        }

        // SELECTION
        ei_new = 0;
        while (ei_new < common.in2_pad_cumv_sel_elem) {
            row = (ei_new + 1) % common.in2_pad_cumv_sel_rows - 1;
            col = (ei_new + 1) / common.in2_pad_cumv_sel_rows + 1 - 1;
            if ((ei_new + 1) % common.in2_pad_cumv_sel_rows == 0) {
                row = common.in2_pad_cumv_sel_rows - 1;
                col -= 1;
            }

            ori_row = row + common.in2_pad_cumv_sel_rowlow - 1;
            ori_col = col + common.in2_pad_cumv_sel_collow - 1;
            punt[bx].d_in2_pad_cumv_sel[ei_new] = punt[bx].d_in2_pad_cumv[ori_col * common.in2_pad_cumv_rows + ori_row];

            ei_new = ei_new + 1;
        }

        // SELECTION 2
        ei_new = 0;
        while (ei_new < common.in2_sub_cumh_elem) {
            row = (ei_new + 1) % common.in2_sub_cumh_rows - 1;
            col = (ei_new + 1) / common.in2_sub_cumh_rows + 1 - 1;
            if ((ei_new + 1) % common.in2_sub_cumh_rows == 0) {
                row = common.in2_sub_cumh_rows - 1;
                col -= 1;
            }

            ori_row = row + common.in2_pad_cumv_sel2_rowlow - 1;
            ori_col = col + common.in2_pad_cumv_sel2_collow - 1;
            punt[bx].d_in2_sub_cumh[ei_new] = punt[bx].d_in2_pad_cumv[ori_col * common.in2_pad_cumv_rows + ori_row];

            ei_new = ei_new + 1;
        }

        // SUBTRACTION
        ei_new = 0;
        while (ei_new < common.in2_sub_cumh_elem) {
            punt[bx].d_in2_sub_cumh[ei_new] = punt[bx].d_in2_pad_cumv_sel[ei_new] - punt[bx].d_in2_sub_cumh[ei_new];
            ei_new = ei_new + 1;
