            ori_col = col + common.in2_sub_cumh_sel2_collow - 1;
            punt[bx].d_in2_sqr_sub2[ei_new] = punt[bx].d_in2_sub_cumh[ori_col * common.in2_sub_cumh_rows + ori_row];

            ei_new = ei_new + 1;
        }

        // SUBTRACTION
        ei_new = 0;
        while (ei_new < common.in2_sub2_elem) {
            punt[bx].d_in2_sqr_sub2[ei_new] = punt[bx].d_in2_sub_cumh_sel[ei_new] - punt[bx].d_in2_sqr_sub2[ei_new];
            ei_new = ei_new + 1;
        }

        //==========================================================================
        // FINAL
        //==========================================================================

        // DENOMINATOR A
        ei_new = 0;
        while (ei_new < common.in2_sub2_elem) {
            temp = punt[bx].d_in2_sub2[ei_new];
            temp2 = punt[bx].d_in2_sqr_sub2[ei_new] - (temp * temp / common.in_elem);
            if (0 > temp2) {
                temp2 = 0;
            }
            punt[bx].d_in2_sqr_sub2[ei_new] = sqrt(temp2);
            ei_new = ei_new + 1;
        }

        // MULTIPLICATION
        ei_new = 0;
        while (ei_new < common.in_sqr_elem) {
            temp = d_in[ei_new];
            punt[bx].d_in_sqr[ei_new] = temp * temp;
            ei_new = ei_new + 1;
        }

        // IN SUM
        ei_new = 0;
        while (ei_new < common.in_cols) {
            sum = 0;
            for (i = 0; i < common.in_rows; i++) {
                sum = sum + d_in[ei_new * common.in_rows + i];
            }
            in_partial_sum[ei_new] = sum;
            ei_new = ei_new + 1;
        }

        // IN_SQR SUM
        ei_new = 0;
        while (ei_new < common.in_sqr_rows) {
            sum = 0;
            for (i = 0; i < common.in_sqr_cols; i++) {
                sum = sum + punt[bx].d_in_sqr[ei_new + common.in_sqr_rows * i];
            }
            in_sqr_partial_sum[ei_new] = sum;
            ei_new = ei_new + 1;
        }

        // FINAL SUMMATION
        in_final_sum = 0;
        for (i = 0; i < common.in_cols; i++) {
            in_final_sum = in_final_sum + in_partial_sum[i];
        }

        in_sqr_final_sum = 0;
        for (i = 0; i < common.in_sqr_cols; i++) {
            in_sqr_final_sum = in_sqr_final_sum + in_sqr_partial_sum[i];
        }

        // DENOMINATOR T
        mean = in_final_sum / common.in_elem;
        mean_sqr = mean * mean;
        variance = (in_sqr_final_sum / common.in_elem) - mean_sqr;
        deviation = sqrt(variance);
        denomT = sqrt((float)(common.in_elem - 1)) * deviation;

        // DENOMINATOR
        ei_new = 0;
        while (ei_new < common.in2_sub2_elem) {
            punt[bx].d_in2_sqr_sub2[ei_new] = punt[bx].d_in2_sqr_sub2[ei_new] * denomT;
            ei_new = ei_new + 1;
        }

        // NUMERATOR
        ei_new = 0;
        while (ei_new < common.conv_elem) {
            punt[bx].d_conv[ei_new] = punt[bx].d_conv[ei_new] - punt[bx].d_in2_sub2[ei_new] * in_final_sum / common.in_elem;
            ei_new = ei_new + 1;
        }

        // CORRELATION
        ei_new = 0;
        while (ei_new < common.in2_sub2_elem) {
            punt[bx].d_in2_sqr_sub2[ei_new] = punt[bx].d_conv[ei_new] / punt[bx].d_in2_sqr_sub2[ei_new];
            ei_new = ei_new + 1;
        }

        //==========================================================================
        // TEMPLATE MASK CREATE
        //==========================================================================

        cent = common.sSize + common.tSize + 1;
        if (common_change.frame_no == 0) {
            tMask_row = cent + punt[bx].d_Row[punt[bx].point_no] - punt[bx].d_Row[punt[bx].point_no] - 1;
            tMask_col = cent + punt[bx].d_Col[punt[bx].point_no] - punt[bx].d_Col[punt[bx].point_no] - 1;
        } else {
            pointer = common_change.frame_no - 1 + punt[bx].point_no * common.no_frames;
            tMask_row = cent + punt[bx].d_tRowLoc[pointer] - punt[bx].d_Row[punt[bx].point_no] - 1;
            tMask_col = cent + punt[bx].d_tColLoc[pointer] - punt[bx].d_Col[punt[bx].point_no] - 1;
        }

        ei_new = 0;
        while (ei_new < common.tMask_elem) {
            location = tMask_col * common.tMask_rows + tMask_row;
            if (location == ei_new) {
                punt[bx].d_tMask[ei_new] = 1;
            } else {
                punt[bx].d_tMask[ei_new] = 0;
            }
            ei_new = ei_new + 1;
        }

        //==========================================================================
        // MASK CONVOLUTION
        //==========================================================================

        ei_new = 0;
        while (ei_new < common.mask_conv_elem) {
            ic = (ei_new + 1) % common.mask_conv_rows;
            jc = (ei_new + 1) / common.mask_conv_rows + 1;
            if ((ei_new + 1) % common.mask_conv_rows == 0) {
                ic = common.mask_conv_rows;
                jc -= 1;
            }

            j = jc + common.mask_conv_joffset;
            jp1 = j + 1;
            if (common.mask_cols < jp1) {
                ja1 = jp1 - common.mask_cols;
            } else {
                ja1 = 1;
            }
            if (common.tMask_cols < j) {
                ja2 = common.tMask_cols;
            } else {
                ja2 = j;
            }

            i = ic + common.mask_conv_ioffset;
            ip1 = i + 1;

            if (common.mask_rows < ip1) {
                ia1 = ip1 - common.mask_rows;
            } else {
                ia1 = 1;
            }
            if (common.tMask_rows < i) {
                ia2 = common.tMask_rows;
            } else {
                ia2 = i;
            }

            s = 0;
            for (ja = ja1; ja2 >= ja; ja++) {
                jb = jp1 - ja;
                for (ia = ia1; ia <= ia2; ia++) {
                    ib = ip1 - ia;
                    s = s + punt[bx].d_tMask[common.tMask_rows * (ja - 1) + ia - 1] * 1;
                }
            }

            punt[bx].d_mask_conv[ei_new] = punt[bx].d_in2_sqr_sub2[ei_new] * s;

            ei_new = ei_new + 1;
        }

        //==========================================================================
        // MAXIMUM VALUE
        //==========================================================================

        // INITIAL SEARCH
        for (ei_new = 0; ei_new < common.mask_conv_rows; ei_new++) {
            largest_value = 0;
            largest_coordinate = 0;
            for (i = 0; i < common.mask_conv_cols; i++) {
                largest_coordinate_current = ei_new * common.mask_conv_rows + i;
                largest_value_current = fabs(punt[bx].d_mask_conv[largest_coordinate_current]);
                if (largest_value < largest_value_current) {
                    largest_coordinate = largest_coordinate_current;
                    largest_value = largest_value_current;
                }
            }
            par_max_coo[ei_new] = largest_coordinate;
            par_max_val[ei_new] = largest_value;
        }

        // FINAL SEARCH
        fin_max_val = 0;
        fin_max_coo = 0;
        for (i = 0; i < common.mask_conv_rows; i++) {
            if (fin_max_val < par_max_val[i]) {
                fin_max_val = par_max_val[i];
                fin_max_coo = par_max_coo[i];
            }
        }

        // convert coordinate to row/col form
        largest_row = (fin_max_coo + 1) % common.mask_conv_rows - 1;
        largest_col = (fin_max_coo + 1) / common.mask_conv_rows;
        if ((fin_max_coo + 1) % common.mask_conv_rows == 0) {
            largest_row = common.mask_conv_rows - 1;
            largest_col -= 1;
        }

        largest_row = largest_row + 1;
        largest_col += 1;
        offset_row = largest_row - common.in_rows - (common.sSize - common.tSize);
        offset_col = largest_col - common.in_cols - (common.sSize - common.tSize);
        pointer = common_change.frame_no + punt[bx].point_no * common.no_frames;
        punt[bx].d_tRowLoc[pointer] = punt[bx].d_Row[punt[bx].point_no] + offset_row;
        punt[bx].d_tColLoc[pointer] = punt[bx].d_Col[punt[bx].point_no] + offset_col;

    } // end if frame_no != 0

    //===============================================================================
    // COORDINATE AND TEMPLATE UPDATE
    //===============================================================================

    if (common_change.frame_no != 0 && (common_change.frame_no) % 10 == 0) {

        loc_pointer = punt[bx].point_no * common.no_frames + common_change.frame_no;
        punt[bx].d_Row[punt[bx].point_no] = punt[bx].d_tRowLoc[loc_pointer];
        punt[bx].d_Col[punt[bx].point_no] = punt[bx].d_tColLoc[loc_pointer];

        d_in = &punt[bx].d_T[punt[bx].in_pointer];

        ei_new = 0;
        while (ei_new < common.in_elem) {
            row = (ei_new + 1) % common.in_rows - 1;
            col = (ei_new + 1) / common.in_rows + 1 - 1;
            if ((ei_new + 1) % common.in_rows == 0) {
                row = common.in_rows - 1;
                col -= 1;
            }

            ori_row = punt[bx].d_Row[punt[bx].point_no] - 25 + row - 1;
            ori_col = punt[bx].d_Col[punt[bx].point_no] - 25 + col - 1;
            ori_pointer = ori_col * common.frame_rows + ori_row;

            d_in[ei_new] = common.alpha * d_in[ei_new] + (1.00 - common.alpha) * common_change.d_frame[ori_pointer];

            ei_new = ei_new + 1;
        }
    }
}

void kernel_launch(void) {
    int bx;
    #pragma omp parallel for schedule(dynamic,1)
    for (bx = 0; bx < common.allPoints; bx++) {
        kernel_function(bx);
    }
}
